import { LegendItem } from '../types/legend.js';

interface LegendItemState {
  visible: boolean;
  updateVisible: (_: boolean) => void;
  updateHoveredState: (_: boolean) => void;
  onLegendIconClick: (_: LegendItem) => void;
  onLegendNameClick: (_: LegendItem, e: MouseEvent) => void;
  onItemHover: (_: LegendItem | undefined, isIconHovered?: boolean) => void;
}

export const useLegendItemInteractions = (
  item: LegendItem,
  state: LegendItemState,
  interactionsDisabled: boolean,
) => {
  const {
    updateVisible,
    updateHoveredState,
    onLegendIconClick,
    onLegendNameClick,
    onItemHover,
    visible,
  } = state;

  const onIconButtonClick = () => {
    if (!interactionsDisabled) {
      updateVisible(!visible);
      onLegendIconClick(item);
    }
  };

  const onNameButtonClick = (event: MouseEvent) => {
    if (!interactionsDisabled) {
      onLegendNameClick(item, event);
      updateVisible(true);
      handleLabelMouseEnter();
    }
  };

  const onNameButtonKeyDown = (event: KeyboardEvent) => {
    if (event.code === 'Enter') {
      event.preventDefault();
      const { ctrlKey, metaKey, shiftKey } = event;
      onNameButtonClick(
        new MouseEvent('click', { ctrlKey, metaKey, shiftKey }),
      );
    }
  };

  const handleMouseEnter = () => {
    if (!interactionsDisabled) {
      onItemHover(visible ? item : undefined);
      updateHoveredState(true);
    }
  };

  const handleLabelMouseEnter = () => {
    handleMouseEnter();
  };

  const handleIconMouseEnter = () => {
    handleMouseEnter();
  };

  const handleMouseLeave = () => {
    onItemHover(undefined);
    updateHoveredState(false);
  };

  return {
    handleLabelMouseEnter,
    handleIconMouseEnter,
    handleMouseLeave,
    onNameButtonClick,
    onNameButtonKeyDown,
    onIconButtonClick,
  };
};
